+	sensor_msgs::Image msg;
+	img_bridge = CvImage(msg.header, sensor_msgs::image_encodings::BGR8, cvImg);
+
+	img_bridge.toImageMsg(msg);
+
+	msg.encoding = "bgr8";
+	msg.header = msg_header;
+	msg.height = i.getHeight();
+	msg.width = i.getWidth();
+
+	return msg;
+}
