+	ros_msg_original_pose.pose.orientation.w = 1;
+
+	// to mrpt
+	mrpt::poses::CPose3DPDFGaussian mrpt_original_pose =
+		mrpt::ros2bridge::fromROS(ros_msg_original_pose);
+
+	EXPECT_EQ(
+		ros_msg_original_pose.pose.position.x, mrpt_original_pose.mean[0]);
+
+#if 0
