+// Declare a test
+TEST(PoseConversions, check_CPose2D_to_ROS)
+{
+	const mrpt::poses::CPose2D p2D(1, 2, 0.56);
+
+	// Convert MRPT->ROS
+	const geometry_msgs::msg::pose ros_p2D = mrpt::ros2bridge::toROS_Pose(p2D);
+
+	// Compare vs. 3D pose:
